def initialize(app, **options)
        @app = app
        if self.class.const_defined?(:Options)
          # Search ancestors so subclasses (e.g. Versioner::Path → Versioner::Base)
          # inherit their parent's Options Data class without redeclaring it.
          @config = self.class::Options.new(**options)
          @options = @config.to_h.freeze
        else
          @options = merge_default_options(options).freeze
        end
        @app_response = nil
      end

def initialize(attrs, options, required, scope, opts)
          @attrs = Array(attrs).freeze
          @options = Grape::Util::DeepFreeze.deep_freeze(options)
          @option = @options # TODO: remove in next major release
          @required = required
          @scope = scope
          @opts = SharedOptions.new(**opts.slice(:allow_blank, :fail_fast))
          @exception_message = message(self.class.default_message_key) if self.class.default_message_key
          @iterator = iterator_class.new(@attrs, @scope).freeze
        end

def initialize(attrs, options, required, scope, opts)
          super

          @exception_message = options.message if options.message

          raw_type = options.type
          type = hash_like?(raw_type) ? raw_type[:value] : raw_type
          @converter =
            if type.is_a?(Grape::Validations::Types::VariantCollectionCoercer)
              type
            else
              Types.build_coercer(type, method: options.coerce_method)
            end
        end

class List
        @app_list_map = Hash.new { |hash, key| hash[key] = new }

        # Returns the +List+ for the application +app+.
        def self.for(app)
          @app_list_map[app]
        end

        # Creates a new +List+ instance.
        def initialize
          @path_watcher_map = Hash.new do |hash, key|
            hash[key] = Watcher.new(key)
          end
        end

